3037 /// A recipe to combine multiple recipes into a single 'expression' recipe,
3038 /// which should be considered a single entity for cost-modeling and transforms.
3039 /// The recipe needs to be 'decomposed', i.e. replaced by its individual
3040 /// expression recipes, before execute. The individual expression recipes are
3041 /// completely disconnected from the def-use graph of other recipes not part of
3042 /// the expression. Def-use edges between pairs of expression recipes remain
3043 /// intact, whereas every edge between an expression recipe and a recipe outside
3044 /// the expression is elevated to connect the non-expression recipe with the
3045 /// VPExpressionRecipe itself.
3046 class VPExpressionRecipe : public VPSingleDefRecipe {
3047   /// Recipes included in this VPExpressionRecipe. This could contain
3048   /// duplicates.
3049   SmallVector<VPSingleDefRecipe *> ExpressionRecipes;
3050 
3051   /// Temporary VPValues used for external operands of the expression, i.e.
3052   /// operands not defined by recipes in the expression.
3053   SmallVector<VPValue *> LiveInPlaceholders;
3054 
3055   enum class ExpressionTypes {
3056     /// Represents an inloop extended reduction operation, performing a
3057     /// reduction on an extended vector operand into a scalar value, and adding
3058     /// the result to a chain.
3059     ExtendedReduction,
3060     /// Represent an inloop multiply-accumulate reduction, multiplying the
3061     /// extended vector operands, performing a reduction.add on the result, and
3062     /// adding the scalar result to a chain.
3063     ExtMulAccReduction,
3064     /// Represent an inloop multiply-accumulate reduction, multiplying the
3065     /// vector operands, performing a reduction.add on the result, and adding
3066     /// the scalar result to a chain.
3067     MulAccReduction,
3068     /// Represent an inloop multiply-accumulate reduction, multiplying the
3069     /// extended vector operands, negating the multiplication, performing a
3070     /// reduction.add on the result, and adding the scalar result to a chain.
3071     ExtNegatedMulAccReduction,
3072   };
3073 
3074   /// Type of the expression.
3075   ExpressionTypes ExpressionType;
3076 
3077   /// Construct a new VPExpressionRecipe by internalizing recipes in \p
3078   /// ExpressionRecipes. External operands (i.e. not defined by another recipe
3079   /// in the expression) are replaced by temporary VPValues and the original
3080   /// operands are transferred to the VPExpressionRecipe itself. Clone recipes
3081   /// as needed (excluding last) to ensure they are only used by other recipes
3082   /// in the expression.
3083   VPExpressionRecipe(ExpressionTypes ExpressionType,
3084                      ArrayRef<VPSingleDefRecipe *> ExpressionRecipes);
3085 
3086 public:
3087   VPExpressionRecipe(VPWidenCastRecipe *Ext, VPReductionRecipe *Red)
3088       : VPExpressionRecipe(ExpressionTypes::ExtendedReduction, {Ext, Red}) {}
3089   VPExpressionRecipe(VPWidenRecipe *Mul, VPReductionRecipe *Red)
3090       : VPExpressionRecipe(ExpressionTypes::MulAccReduction, {Mul, Red}) {}
3091   VPExpressionRecipe(VPWidenCastRecipe *Ext0, VPWidenCastRecipe *Ext1,
3092                      VPWidenRecipe *Mul, VPReductionRecipe *Red)
3093       : VPExpressionRecipe(ExpressionTypes::ExtMulAccReduction,
3094                            {Ext0, Ext1, Mul, Red}) {}
3095   VPExpressionRecipe(VPWidenCastRecipe *Ext0, VPWidenCastRecipe *Ext1,
3096                      VPWidenRecipe *Mul, VPWidenRecipe *Sub,
3097                      VPReductionRecipe *Red)
3098       : VPExpressionRecipe(ExpressionTypes::ExtNegatedMulAccReduction,
3099                            {Ext0, Ext1, Mul, Sub, Red}) {
3100     assert(Mul->getOpcode() == Instruction::Mul && "Expected a mul");
3101     assert(Red->getRecurrenceKind() == RecurKind::Add &&
3102            "Expected an add reduction");
3103     assert(getNumOperands() >= 3 && "Expected at least three operands");
3104     [[maybe_unused]] auto *SubConst = dyn_cast<ConstantInt>(getOperand(2)->getLiveInIRValue());
3105     assert(SubConst && SubConst->getValue() == 0 &&
3106            Sub->getOpcode() == Instruction::Sub && "Expected a negating sub");
3107   }
3108 
3109   ~VPExpressionRecipe() override {
3110     SmallPtrSet<VPSingleDefRecipe *, 4> ExpressionRecipesSeen;
3111     for (auto *R : reverse(ExpressionRecipes)) {
3112       if (ExpressionRecipesSeen.insert(R).second)
3113         delete R;
3114     }
3115     for (VPValue *T : LiveInPlaceholders)
3116       delete T;
3117   }
3118 
3119   VP_CLASSOF_IMPL(VPDef::VPExpressionSC)
3120 
3121   VPExpressionRecipe *clone() override {
3122     assert(!ExpressionRecipes.empty() && "empty expressions should be removed");
3123     SmallVector<VPSingleDefRecipe *> NewExpressiondRecipes;
3124     for (auto *R : ExpressionRecipes)
3125       NewExpressiondRecipes.push_back(R->clone());
3126     for (auto *New : NewExpressiondRecipes) {
3127       for (const auto &[Idx, Old] : enumerate(ExpressionRecipes))
3128         New->replaceUsesOfWith(Old, NewExpressiondRecipes[Idx]);
3129       // Update placeholder operands in the cloned recipe to use the external
3130       // operands, to be internalized when the cloned expression is constructed.
3131       for (const auto &[Placeholder, OutsideOp] :
3132            zip(LiveInPlaceholders, operands()))
3133         New->replaceUsesOfWith(Placeholder, OutsideOp);
3134     }
3135     return new VPExpressionRecipe(ExpressionType, NewExpressiondRecipes);
3136   }
