3138   /// Return the VPValue to use to infer the result type of the recipe.
3139   VPValue *getOperandOfResultType() const {
3140     unsigned OpIdx =
3141         cast<VPReductionRecipe>(ExpressionRecipes.back())->isConditional() ? 2
3142                                                                            : 1;
3143     return getOperand(getNumOperands() - OpIdx);
3144   }
