1589 void VPlanTransforms::simplifyRecipes(VPlan &Plan) {
1590   ReversePostOrderTraversal<VPBlockDeepTraversalWrapper<VPBlockBase *>> RPOT(
1591       Plan.getEntry());
1592   VPTypeAnalysis TypeInfo(Plan);
1593   for (VPBasicBlock *VPBB : VPBlockUtils::blocksOnly<VPBasicBlock>(RPOT)) {
1594     for (VPRecipeBase &R : make_early_inc_range(*VPBB))
1595       if (auto *Def = dyn_cast<VPSingleDefRecipe>(&R))
1596         simplifyRecipe(Def, TypeInfo);
1597   }
1598 }
